import React from 'react'
import { useModel, useSetModelState, useModelGetItems } from '@airiot/client'
import FilterSchemaForm from '../filter-form/filter-form'
import _ from 'lodash'

interface ViewFilterProps {
  filters?: Array<{
    key: string
    name: string
  }>
  classNames?: Record<'form' | 'group' | 'field' | 'label' | 'input' | 'description' | 'error', string>
}

const ViewFilter: React.FC<ViewFilterProps> = ({
  filters = [],
  classNames
}) => {
  const { model } = useModel()
  const setWheres = useSetModelState('wheres')
  const { getItems } = useModelGetItems()

  const properties = _.mapValues(model.properties || {}, (prop, key) => ({ ...prop, name: key }))
  const onSubmit = (value: any) => {
    setWheres((w: any) => {
      return { ...w, filter: { ...w.filter, ...value } }
    });
    getItems()
  }

  const onReset = (reset: () => void) => {
    // 重置表单
    reset()
    // 重置查询条件
    setWheres((w: any) => {
      return { ...w, filter: {} }
    });
    getItems()
  }

  return (
    <FilterSchemaForm formId={model.name || ''} schema={{ ...model, properties }} formSchema={filters} classNames={classNames} onSubmit={onSubmit} >
      {(methods) => (
        <div className="mt-6 pt-4 border-t border-slate-200 flex gap-2">
          <button
            type="button"
            onClick={() => onReset(methods.reset)}
            className="flex-1 bg-white border border-slate-300 text-slate-700 py-2 px-4 rounded-md hover:bg-slate-50 transition-colors"
          >
            重置
          </button>
          <button
            type="submit"
            className="flex-1 bg-blue-500 text-white py-2 px-4 rounded-md hover:bg-blue-600 transition-colors"
          >
            搜索
          </button>
        </div>
      )}
    </FilterSchemaForm>
  )
}

export default ViewFilter

import {
  FieldGroup
} from "@/components/ui/field"
import { FormProvider, useForm, useFilterSchema, type UseFormPropsExtended, type UseFormSchemaProps } from '@airiot/client'
import type { ReactNode } from 'react'
import _ from "lodash"
import FormField from "@/registry/components/form-field/form-field"

type SchemaFormProps = UseFormPropsExtended & UseFormSchemaProps & {
  formId: string
  onSubmit: (data: any) => void
  children?: ReactNode | ((props: any) => ReactNode)
  classNames?: Record<'form' | 'group' | 'field' | 'label' | 'input' | 'description' | 'error', string>
}

const FilterSchemaForm = ({ schema, formSchema, onSubmit, formId, children, classNames, ...props }: SchemaFormProps) => {

  const { fields } = useFilterSchema({ schema, formSchema })
  const methods = useForm(props)

  return (
    <FormProvider {...methods} classNames={classNames}>
      <form id={formId} onSubmit={methods.handleSubmit(onSubmit)} className={classNames?.form}>
        <FieldGroup className={classNames?.group}>
          {fields.map(field => (
            <FormField {...field} name={field.key || ''} key={field.key} />
          ))}
        </FieldGroup>
        {children ? ( typeof children === 'function' ? children({
          ...methods
        }) : children ) : null}
      </form>
    </FormProvider>
  )
}

export default FilterSchemaForm
